import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface SubjectBreakdown {
  subject: string;
  hours: number;
}

interface WeeklyComparison {
  day: string;
  hours: number;
}

interface StudyData {
  dailyStudyHours: number;
  subjectBreakdown: SubjectBreakdown[];
  weeklyComparison: WeeklyComparison[];
}

export default function Widget() {
  const studyData = response.data as StudyData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#1E1E1E' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#F5A623', mb: 1 }}>
              Daily Study Hours
            </Typography>
            <Typography variant="h4" sx={{ color: '#4A90E2', fontWeight: 700 }}>
              {studyData.dailyStudyHours} hrs
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" sx={{ color: '#F5A623', mb: 1 }}>
              Subject Breakdown
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {studyData.subjectBreakdown.map((subject) => (
                <Box key={subject.subject} sx={{ textAlign: 'center', color: '#FFFFFF' }}>
                  <Typography variant="body2">{subject.subject}</Typography>
                  <Typography variant="caption">{subject.hours} hrs</Typography>
                </Box>
              ))}
            </Stack>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <BarChart
              height={140}
              series={[
                {
                  data: studyData.weeklyComparison.map(d => d.hours),
                  color: '#4A90E2',
                },
              ]}
              xAxis={[
                {
                  data: studyData.weeklyComparison.map(d => d.day),
                  scaleType: 'band',
                  tickLabelStyle: {
                    fontSize: 11,
                    fill: '#FFFFFF',
                  },
                }
              ]}
              margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
              sx={{
                '& .MuiBarElement-root': {
                  rx: 4,
                },
              }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
